import type {
  AIPromptSystem as SchemaAIPromptSystem,
  AttributeRelevanceMatrix as SchemaAttributeRelevanceMatrix,
  AttributeRole as SchemaAttributeRole,
  AttributeSystem as SchemaAttributeSystem,
  CategoryConfiguration as SchemaCategoryConfiguration,
  CategorySignals as SchemaCategorySignals,
  ProcessingConfig as SchemaProcessingConfig,
  ProcessingSettings as SchemaProcessingSettings,
  RulePattern as SchemaRulePattern,
  SubtypeDefinition as SchemaSubtypeDefinition,
  TopLevelCategory as SchemaTopLevelCategory,
} from '../config/category-config-schema';

/**
 * Category configuration types derived directly from the canonical Zod schemas.
 * This keeps compile-time types in lock-step with runtime validation behaviour.
 */

export type CategoryConfiguration = SchemaCategoryConfiguration;
export type ProcessingConfig = SchemaProcessingConfig;
export type ProcessingSettings = SchemaProcessingSettings;
export type CategorySignals = SchemaCategorySignals;
export type TopLevelCategory = SchemaTopLevelCategory;
export type SubtypeDefinition = SchemaSubtypeDefinition;
export type RulePattern = SchemaRulePattern;
export type AttributeSystem = SchemaAttributeSystem;
export type AttributeRelevanceMatrix = SchemaAttributeRelevanceMatrix;
export type AttributeRole = SchemaAttributeRole;
export type AIPromptSystem = SchemaAIPromptSystem;

/**
 * Derived helper types for convenience, all guaranteed to match the schema.
 */

// Removed: ConfidenceThresholds and MultiLabelPolicy - migrated to ProcessingSettings.multiLabelSelection
export type MultiLabelSelectionSettings = ProcessingSettings['multiLabelSelection'];
export type AIRoutingSettings = ProcessingSettings['aiRouting'];
export type HardAssertionsSettings = ProcessingSettings['hardAssertions'];
export type DomainOverrides = ProcessingConfig['domainSignalOverrides'];
export type DomainResolution = ProcessingConfig['domainSignalResolution'];
export type AttributeSchema = AttributeSystem['schema'][string];
export type AttributeDetector = AttributeSystem['detectors'][number];
export type DerivedAttribute = AttributeSystem['derived'][string];
export type AttributeInfluenceMatrix = NonNullable<CategoryConfiguration['attributeMatrix']>;
export type CompiledRule = NonNullable<CategoryConfiguration['compiledRules']>[number];
export type JSONSchema = ProcessingConfig['featureExtractionSchema'];
export type JSONSchemaProperty = JSONSchema['properties'][string];

/**
 * Valid Minimal Category Config Fixture
 *
 * Purpose: Provides a minimal but valid CategoryConfiguration object that passes Zod validation
 * for use in unit and integration tests.
 *
 * This fixture represents the full configuration wrapper including validation metadata,
 * whereas validMinimalProcessingConfig represents just the processingConfig section.
 *
 * Usage:
 * ```typescript
 * import { validMinimalCategoryConfig } from '@classification-engine/tests/fixtures/configs';
 *
 * const config = validMinimalCategoryConfig;
 * // Or customize:
 * const customConfig = {
 *   ...validMinimalCategoryConfig,
 *   processingConfig: {
 *     ...validMinimalCategoryConfig.processingConfig,
 *     version: 2,
 *   },
 * };
 * ```
 */

import { CategoryConfiguration } from '../../../src/types/category-configuration';
import { validMinimalProcessingConfig } from './valid-minimal-processing-config';

import { createHash } from 'crypto';

/**
 * Generate a SHA-256 hash for configuration validation
 *
 * @param content - Content to hash
 * @returns 64-character SHA-256 hash
 */
function generateConfigHash(content: string): string {
  return createHash('sha256').update(content).digest('hex');
}

/**
 * Minimal valid CategoryConfiguration for testing
 *
 * Includes all required fields per the CategoryConfigurationSchema from
 * packages/classification-engine/src/config/category-config-schema.ts
 */
export const validMinimalCategoryConfig: CategoryConfiguration = {
  // Metadata
  version: '1.0.0', // Semantic version format
  lastModified: new Date('2025-09-27T00:00:00.000Z'),
  hash: generateConfigHash(JSON.stringify(validMinimalProcessingConfig)),

  // Main processing configuration
  processingConfig: validMinimalProcessingConfig,

  // Validation metadata
  schemaVersion: '1.0.0',
  validationPassed: true,
  validationErrors: [],

  // Runtime optimization (empty arrays for test configs)
  compiledRules: [],
  attributeMatrix: {},
};

/**
 * Minimal valid CategoryConfiguration with one test category
 *
 * Useful for tests that need at least one category defined
 */
export const validMinimalCategoryConfigWithCategory: CategoryConfiguration = {
  ...validMinimalCategoryConfig,
  processingConfig: {
    ...validMinimalProcessingConfig,
    categorySignals: {
      TEST_CATEGORY: {
