/**
 * Email Delivery Service (T047) - SMTP Implementation
 *
 * Handles SMTP email delivery with nodemailer:
 * - SMTP connection configuration and verification
 * - Email formatting (from, to, subject, HTML/plain text)
 * - Delivery status tracking with retry logic
 * - Error recovery and detailed error reporting
 *
 * Integrates with:
 * - DigestGenerator (T046) for EmailDigest input
 * - nodemailer for SMTP transport
 */

import nodemailer, { type Transporter, type SendMailOptions, type SentMessageInfo } from 'nodemailer';
import type { EmailDigest } from '../types/email-digest';

/**
 * SMTP configuration for email delivery
 */
export interface SMTPConfig {
  /** SMTP server hostname */
  host: string;
  /** SMTP server port (587 for TLS, 465 for SSL) */
  port: number;
  /** Use TLS/SSL connection */
  secure: boolean;
  /** Authentication credentials */
  auth: {
    /** SMTP username */
